    .setKey(process.env.APPWRITE_API_KEY);

const storage = new Storage(client);

// Create bucket (server-side, no user context needed)
const bucket = await storage.createBucket({
    bucketId: ID.unique(),
    name: 'server-uploads',
    permissions: [
        Permission.read(Role.any()),
        Permission.create(Role.users()),
        Permission.update(Role.users()),
        Permission.delete(Role.users()),
    ],
});

// Upload file from server filesystem
const file = await storage.createFile({
    bucketId: bucket.$id,
    fileId: ID.unique(),
    file: InputFile.fromPath('/path/to/image.jpg', 'image.jpg'),
    permissions: [
        Permission.read(Role.any()),
        Permission.update(Role.user('[USER_ID]')),
        Permission.delete(Role.user('[USER_ID]')),
    ],
});

// Get preview URL
const previewUrl = storage.getFilePreview({
    bucketId: bucket.$id,
    fileId: file.$id,
    width: 400,
});
*/
```

## Key Points

| Component | Description |
|-----------|-------------|
| **Bucket permissions** | Set at bucket level to inherit defaults for all files |
| **File permissions** | Override bucket defaults per-file (optional) |
| **`Role.any()`** | Allows public access (anyone can read) |
| **`Role.users()`** | Only authenticated users can upload |
| **`Role.user(id)`** | Specific user can modify/delete their uploads |
| **`getFilePreview()`** | Returns a URL (not binary) for displaying images |

> **Security tip:** Use `Role.any()` only with `read` permissions. Avoid granting `create`, `update`, or `delete` with `Role.any()` to prevent unauthorized modifications.

# Push Notifications with Appwrite Messaging

Appwrite Messaging supports push notifications across multiple platforms. Here's what you need to know:

## Supported Providers

| Provider | Platform | Description |
|----------|----------|-------------|
| **FCM** | Android | Firebase Cloud Messaging |
| **APNS** | iOS | Apple Push Notification service |
| **Expo** | iOS/Android | For Expo-managed apps |
| **Pushwoosh** | Cross-platform | Alternative provider |

---

## Setup Steps

### 1. Configure Provider Credentials

In the **Appwrite Console** → **Messaging** → **Providers**, add your credentials:

**For FCM (Android):**
- Upload your `google-services.json` or provide the server key

**For APNS (iOS):**
- Upload your `.p12` certificate or `.p8` key
- Configure the sandbox/production endpoint

### 2. Register Devices (Client-side)

```typescript
// Web / React Native
import { Messaging } from 'appwrite';

const messaging = new Messaging(client);

// Register a device for push notifications
const subscription = await messaging.createSubscription(
    '[PROVIDER_ID]',  // e.g., 'fcm' or 'apns'
    '[TOKEN]'         // device push token from Firebase/APNS
);
```

### 3. Create a Topic (Target)

```typescript
// Server-side with node-appwrite
import { Messaging } from 'node-appwrite';

const messaging = new Messaging(client);

// Create a topic
const topic = await messaging.createTopic(
    '[TOPIC_ID]',      // unique identifier
    '[TOPIC_NAME]'     // human-readable name
);
```

### 4. Subscribe Devices to a Topic

```typescript
// Subscribe devices to a topic
await messaging.createTopicSubscriptions(
    '[TOPIC_ID]',
    [
        { targetId: '[SUBSCRIPTION_ID_1]' },
        { targetId: '[SUBSCRIPTION_ID_2]' }
    ]
);
```

---

## Sending a Push Notification to a Topic

### Server-side (Node.js)

```typescript
const messaging = new Messaging(client);

await messaging.createPush(
    '[MESSAGE_ID]',           // unique message ID
    '[TITLE]',                // notification title
    '[BODY]',                 // notification body
    null,                     // no specific user IDs
    {
        topics: ['[TOPIC_ID]']  // target the topic
    },
    {
        subtitle: 'Optional subtitle',
        body: '[BODY]',
        sound: 'default',
        icon: 'icon_url',
        clickAction: 'OPEN_ACTIVITY'
    }
);
```

### Sending to Multiple Targets

```typescript
await messaging.createPush(
    ID.unique(),
    'New Update Available!',
    'Version 2.0 is now ready to download.',
    null,
    {
        // Send to multiple topics
        topics: ['announcements', 'beta-testers']
    },
    {
        body: 'Check out the new features in this release.'
    }
);
```

---

## Client-side Push Registration (React Native Example)

```typescript
import { Messaging } from 'react-native-appwrite';

// Request permission and get token
async function setupPushNotifications(providerId: string) {
    // Get FCM/APNS token from your native layer
    const token = await getPushToken(); // from Firebase/APNS native SDK

    // Register with Appwrite
    await messaging.createSubscription(providerId, token);

    // Or subscribe to a topic directly
