    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1') // e.g. https://cloud.appwrite.io/v1
    .setProject('[YOUR_PROJECT_ID]');

const storage = new Storage(client);

// 2. Upload a file with permissions (from a file input)
async function uploadImage(file: File) {
    try {
        const uploadedFile = await storage.createFile({
            bucketId: '[YOUR_BUCKET_ID]',           // e.g. 'images'
            fileId: ID.unique(),
            file: file,                             // File object from <input type="file">
            permissions: [
                Permission.read(Role.any()),        // Anyone can view the file
                Permission.update(Role.user('[USER_ID]')), // Specific user can update
                Permission.delete(Role.user('[USER_ID]'))  // Specific user can delete
                // Or use Role.team('[TEAM_ID]') for team-based access
            ]
        });

        console.log('File uploaded:', uploadedFile.$id);

        // 3. Get preview URL for the image
        const previewUrl = storage.getFilePreview({
            bucketId: '[YOUR_BUCKET_ID]',
            fileId: uploadedFile.$id,
            width: 400,      // optional
            height: 400,     // optional
            quality: 80      // optional
        });

        // Use the URL directly (it's a string)
        console.log('Preview URL:', previewUrl);
        // Example: <img src={previewUrl} alt="preview" />

        return { file: uploadedFile, previewUrl };
    } catch (error) {
        console.error('Upload failed:', error);
        throw error;
    }
}

// Usage example (in a browser event handler)
const fileInput = document.getElementById('file-input') as HTMLInputElement;
fileInput.onchange = async () => {
    if (fileInput.files?.[0]) {
        await uploadImage(fileInput.files[0]);
    }
};
```

### Key Points
- **Permissions**: Use `Permission.read/update/delete(Role.any() | Role.user(id) | Role.team(id))`. Always include them on `createFile` for per-file control.
- **Preview URL**: `getFilePreview()` returns a URL string you can use directly in `<img src>`. Supports `width`, `height`, `quality`, `gravity`, etc.
- **Bucket creation**: Do this once in the Appwrite Console (or via server SDK with `storage.createBucket(...)` using an API key).
- Replace placeholders (`[YOUR_PROJECT_ID]`, `[YOUR_BUCKET_ID]`, `[USER_ID]`) with your actual values.

This follows the latest Appwrite TypeScript/Web SDK patterns.

**Setting up push notifications with Appwrite Messaging**

Appwrite Messaging lets you send push notifications (along with email/SMS) using topics for grouping subscribers. Setup happens mostly in the Appwrite Console, with SDK calls for targets, subscribers, and sending.

### 1. Create a Push Provider
In the Appwrite Console → **Messaging** → **Providers** → **Create Provider**.

**Supported push providers**:
- **FCM (Firebase Cloud Messaging)**: Works for Android, iOS (via FCM), and web push. Requires a Firebase service account JSON or server key.
- **APNS (Apple Push Notification service)**: For iOS/macOS. Requires a `.p8` private key, Key ID, Team ID, and bundle ID.

You can create multiple providers (e.g., one FCM + one APNS) and choose which to use per message or target. No other push providers (like OneSignal) are natively supported.

### 2. Create a Topic
In **Messaging** → **Topics** → **Create Topic**.  
Topics let you broadcast to groups of subscribers (e.g., "news", "promotions").

### 3. Register Device Tokens & Subscribe to Topics
On the client (mobile/web app):
- Use the platform SDK (Firebase for FCM, or Apple’s PushKit/UserNotifications for APNS) to obtain a device push token.
- Use the Appwrite SDK to create a **target** (the push endpoint) and **subscribe** it to your topic.

**TypeScript SDK example** (client-side with user session or server-side with API key):

```typescript
import { Client, Messaging, ID } from 'appwrite'; // or 'node-appwrite' / 'react-native-appwrite'

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('YOUR_PROJECT_ID')
  .setKey('YOUR_API_KEY'); // server-side; use session for client

const messaging = new Messaging(client);

// 1. Create a push target (device token + provider)
const target = await messaging.createTarget({
  targetId: ID.unique(),
  providerId: 'YOUR_FCM_PROVIDER_ID', // or APNS provider ID
  providerType: 'push',
  identifier: 'DEVICE_PUSH_TOKEN_HERE',
  name: 'User Device'
});

// 2. Subscribe the target to a topic
const subscriber = await messaging.createSubscriber({
  topicId: 'YOUR_TOPIC_ID',
  targetId: target.$id,
  // userId: 'optional-user-id' // if linking to a specific Appwrite user
});
```

**Permissions note**: The API key or user session must have `write` permission on the topic.

### 4. Send a Push Notification to a Topic
Use the server SDK (API key) to send. Messages can target topics, specific users, or targets.

```typescript
const messaging = new Messaging(client);

const message = await messaging.createMessage({
  messageId: ID.unique(),
  topics: ['YOUR_TOPIC_ID'],           // send to everyone subscribed to this topic
  // users: ['USER_ID'],               // alternative: specific users
  // targets: ['TARGET_ID'],           // alternative: specific targets
  title: 'Hello from Appwrite!',
  body: 'This is a push notification.',
  // Push-specific options (passed to FCM/APNS)
  data: { customKey: 'value' },        // custom payload
  // icon, sound, badge, etc. can be included in data or via provider config
  scheduledAt: '2025-12-31T12:00:00Z'  // optional: schedule for later
});
```

### Additional Notes
- **Client-side handling**: Your mobile app must still integrate the native push SDK to receive and display notifications (Appwrite only delivers them).
- **Testing**: Use the Console’s “Send test message” or the SDK with a draft message.
- **Limits & billing**: Push delivery counts toward your Messaging quota. FCM/APNS have their own rate limits.
- **Real-time feedback**: Listen to message status via the Console or by querying message logs.

For the latest credential formats or advanced options (e.g., web push, rich notifications), check the Appwrite Console UI or the official Messaging docs.

**Appwrite Messaging** targets messages using three primary mechanisms: **users**, **topics**, and **individual targets**. These are specified when creating a message (via `createEmail`, `createSms`, `createPush`, or the general `createMessage` method). Appwrite resolves the targets automatically based on what you provide.

### Targeting Options

- **Specific Users** (`users` array):  
  Send to one or more users by their `$id`. Appwrite delivers the message to **all targets** (email, phone, push device) associated with those users.  
  Example: `users: ['user_abc123', 'user_def456']`

- **Topics** (`topics` array):  
  Topics are named groups. Users (or devices) subscribe to topics. Sending to a topic delivers the message to **all subscribed targets**.  
  Example: `topics: ['news', 'promotions']`  
  Use `createTopic()` to create topics and `createSubscriber()` to subscribe users/targets.

- **Individual Targets** (`targets` array):  
  Targets are specific endpoints (e.g., a device token for push, an email address, or phone number). Target IDs come from the `targets` collection.  
  Example: `targets: ['target_xyz789']`  
  This is the most granular option—useful for direct device or contact targeting.

You can only use **one** of `users`, `topics`, or `targets` per message (they are mutually exclusive in the API).

### Example (Server-side TypeScript SDK)

```typescript
import { Client, Messaging, ID } from 'node-appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject(process.env.APPWRITE_PROJECT_ID)
  .setKey(process.env.APPWRITE_API_KEY);

const messaging = new Messaging(client);

// Send to specific users
const msg1 = await messaging.createEmail({
  messageId: ID.unique(),
  subject: 'Welcome!',
  content: 'Thanks for signing up.',
  users: ['user_abc123'],           // targets all of this user's endpoints
  // draft: false,                  // optional
  // scheduledAt: '2025-...'        // optional
});

// Send to a topic
const msg2 = await messaging.createPush({
  messageId: ID.unique(),
  title: 'New Update',
  body: 'Check out the latest features.',
  topics: ['product-updates'],
});

// Send to individual targets
const msg3 = await messaging.createSms({
  messageId: ID.unique(),
  content: 'Your verification code is 123456',
  targets: ['target_phone_001'],
});
```

### Additional Notes
- **Providers** must be configured first (SMTP/Mailgun for email, Twilio for SMS, FCM/APNs for push).
- Use `listTargets()`, `listTopics()`, and `listSubscribers()` to manage and discover IDs.
- Messages can be scheduled or sent as drafts.
- Permissions and rate limits apply at the project level.

This targeting model gives flexible, scalable delivery without manually managing every endpoint.

**To send a push notification to all users subscribed to a topic in Appwrite, the following must be configured first:**

- **A push notification provider** (FCM for Android or APNS for iOS) must be added and enabled in the Appwrite Console under **Messaging → Providers**. You need valid credentials (e.g., Firebase service account JSON or APNS certificates).
- A **Topic** must be created in **Messaging → Topics**.
- Users/devices must have **push targets** created (with their device tokens) and **subscribed** to the topic (via `createSubscriber`).

### Steps to Send the Notification

1. **On the client side** (after obtaining the device push token):
   - Create a push target using the server SDK or console.
   - Subscribe the target to your topic:
     ```typescript
     import { Client, Messaging, ID } from 'node-appwrite'; // or 'appwrite' for client

     const messaging = new Messaging(client);

     // Create target (server-side)
     const target = await messaging.createTarget({
       targetId: ID.unique(),
       providerType: 'push',
       providerId: '[YOUR_PROVIDER_ID]',
       identifier: 'device-push-token-here',
       name: 'User Device'
     });

     // Subscribe target to topic
     await messaging.createSubscriber({
       topicId: '[TOPIC_ID]',
       targetId: target.$id,
       subscriberId: ID.unique()
     });
     ```

2. **Send the message** (server-side or via Console):
   - Use `createMessage` targeting the topic (this automatically reaches all subscribers):
     ```typescript
     const message = await messaging.createMessage({
       messageId: ID.unique(),
       topics: ['[TOPIC_ID]'],           // sends to all subscribers of the topic
       // users: [],                     // optional: specific users
       // targets: [],                   // optional: specific targets
       content: JSON.stringify({        // push payload
         title: 'Hello!',
         body: 'This is a push notification.',
         data: { key: 'value' }
       }),
       // draft: false,                  // set to true to save as draft
       // scheduledAt: '...'             // optional scheduling
     });
     ```

3. **Monitor delivery** in the Appwrite Console under **Messaging → Messages** (shows status, delivery stats, and errors).

**Notes**:
- Push notifications require the provider to be active and the app to be properly configured for push (Firebase/APNS setup on the mobile/web side).
- Use the server SDK (`node-appwrite`) with an API key for admin operations like creating targets/messages.
- Topics support multiple channels (push, email, SMS) — the message will only deliver via push if a push provider is configured.

```typescript
import { Client, Realtime, Channel } from 'appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const realtime = new Realtime(client);

const subscription = realtime.subscribe([
    Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
    Channel.bucket('[BUCKET_ID]').file()
], (response) => {
    const events = response.events || [];
    const payload = response.payload;

    if (events.some(e => e.includes('.rows.'))) {
        // Handle table row changes (create/update/delete)
        console.log('Row change:', events, payload);
        // e.g., if (events[0].endsWith('.create')) { ... }
    } else if (events.some(e => e.includes('.files.'))) {
        // Handle file uploads/changes
        console.log('File event:', events, payload);
        // e.g., if (events[0].endsWith('.create')) { ... }
    }
});

// To unsubscribe later:
// subscription.close();
```

**Exact channel strings:**

```ts
realtime.subscribe([
  'tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows',
  'buckets.[BUCKET_ID].files'
], (response) => {
  // response.events, response.payload, etc.
});
```

(Replace `[DATABASE_ID]`, `[TABLE_ID]`, and `[BUCKET_ID]` with your actual IDs. The `Channel` helper produces the same strings.)

Here is the complete code to implement email and password signup and login using the Appwrite Web SDK.

### 1. Install the SDK
First, ensure you have the Appwrite Web SDK installed in your project:
```bash
npm install appwrite
```

### 2. Implementation

Here is the complete code including setting up the client, creating a new user account, and logging them in by creating a session.

```javascript
import { Client, Account, ID, AppwriteException } from 'appwrite';

// 1. Set up the Appwrite Client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1') // Replace with your endpoint
    .setProject('[PROJECT_ID]'); // Replace with your project ID

// Initialize the Account service
const account = new Account(client);

/**
 * Sign up a new user
 */
async function signUp(email, password, name) {
    try {
        // Create a new account
        const user = await account.create({
            userId: ID.unique(),
            email: email,
            password: password,
            name: name
        });

        console.log('Account created successfully:', user);
        return user;
    } catch (error) {
        if (error instanceof AppwriteException) {
            console.error('Signup failed:', error.message);
        }
        throw error;
    }
}

/**
 * Log in an existing user
 */
async function logIn(email, password) {
    try {
        // Create a session (logs the user in)
        const session = await account.createEmailPasswordSession({
            email: email,
            password: password
        });

        console.log('Logged in successfully. Session:', session);
        return session;
    } catch (error) {
        if (error instanceof AppwriteException) {
            console.error('Login failed:', error.message);
        }
        throw error;
    }
}

// --- Example Usage ---
async function authenticateUser() {
    const email = 'user@example.com';
    const password = 'securePassword123!';
    const name = 'John Doe';

    // 1. Sign up
    await signUp(email, password, name);

    // 2. Log in
    await logIn(email, password);

    // 3. Verify the user is logged in by fetching their account details
    const currentUser = await account.get();
    console.log('Current User:', currentUser.name);
}
```

### Key Notes:
* **`ID.unique()`**: Generates a unique ID for the new user. You can also pass a custom string if you prefer to manage IDs yourself.
* **`createEmailPasswordSession`**: This method creates a persistent session for the user. The Appwrite Web SDK automatically stores the session cookie/token in the browser, so subsequent requests to Appwrite services (like databases or storage) will be authenticated automatically.

In Appwrite, a **session** represents an authenticated user's active login state. Sessions are tied to a specific user and device/browser, allowing users to interact with secure resources based on their permissions.

Here is a breakdown of how Appwrite sessions are created, managed, deleted, and limited.

### 1. Creating Sessions
Sessions are created when a user logs in. Appwrite supports multiple authentication methods, including Email/Password, OAuth2, Magic URLs, and Anonymous logins.

**Client-Side (Web / Mobile):**
When you create a session on the client, the Appwrite SDK automatically stores the session token (usually in a secure cookie or local storage) and attaches it to subsequent requests.
```typescript
const account = new Account(client);

// Email/Password Login
const session = await account.createEmailPasswordSession({
    email: 'user@example.com',
    password: 'password123'
});

// OAuth2 Login (Web)
account.createOAuth2Session({
    provider: OAuthProvider.Github,
    success: 'https://example.com/success',
    failure: 'https://example.com/fail'
});
```

**Server-Side Rendering (SSR):**
In SSR frameworks (Next.js, Nuxt, etc.), you use an Admin API key to create the session, extract the `secret`, and manually set it as a secure cookie named `a_session_[PROJECT_ID]`.
```typescript
// 1. Admin client creates the session
const session = await account.createEmailPasswordSession({ email, password });

// 2. Set the session secret as an HttpOnly cookie
res.cookie('a_session_[PROJECT_ID]', session.secret, {
    httpOnly: true,
    secure: true,
    sameSite: 'strict',
    expires: new Date(session.expire),
    path: '/',
});
```

### 2. Managing Sessions
Once a session is active, you can use it to identify the user and perform actions on their behalf.

*   **Client-Side:** The SDK handles session management automatically. You can fetch the currently logged-in user's details using `await account.get()`.
*   **Server-Side (SSR):** You must read the session cookie from the incoming request and apply it to a fresh, per-request client using `client.setSession(secret)`. **Never share a session client across different users' requests.**
    ```typescript
    const sessionClient = new Client()
        .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
        .setProject('[PROJECT_ID]')
        .setSession(req.cookies['a_session_[PROJECT_ID]']); // Apply the user's session
    ```

### 3. Deleting Sessions (Logout)
To log a user out, you delete their session. You can delete the current session or target a specific session ID (which is useful if you want to log a user out of a different device remotely).

```typescript
// Delete the current active session
await account.deleteSession({ sessionId: 'current' });

// Delete a specific session by its ID
await account.deleteSession({ sessionId: '[SESSION_ID]' });
```
*(Note: For SSR apps, you must also clear the `a_session_[PROJECT_ID]` cookie from the user's browser).*

### 4. Session Limits & Expiration
*   **Multiple Active Sessions:** Appwrite allows a single user to have multiple active sessions simultaneously (e.g., logged in on a mobile app and a desktop browser at the same time). You can list all active sessions for a user using `account.listSessions()`.
*   **Expiration:** Sessions are not permanent. When a session is created, it returns an `expire` property (an ISO 8601 timestamp). By default, Appwrite sessions expire after **1 year**, but this duration can be configured in your Appwrite Console settings.
*   **Rate Limiting:** To prevent brute-force attacks, Appwrite enforces rate limits on session creation endpoints (e.g., a maximum number of login attempts per IP/user within a specific timeframe). If this limit is exceeded, Appwrite will return a `429 Too Many Requests` error, and the user must wait before trying again.

In Appwrite, **creating databases and tables is a server-side only operation** for security reasons. You cannot create them directly from the client-side Web SDK. 

To accomplish your goal, you will use the Server SDK (`node-appwrite`) to provision the database and table, and the Web SDK (`appwrite`) to insert the row from your client application. 

Here is the code for both steps using the current `TablesDB` API:

### 1. Server-Side: Create Database and Table
Run this in your Node.js backend or an Appwrite Function to set up your schema.

```typescript
import { Client, TablesDB, ID } from 'node-appwrite';

const serverClient = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('<PROJECT_ID>')
    .setKey('<YOUR_API_KEY>');

const serverTablesDB = new TablesDB(serverClient);

async function setupDatabase() {
    // 1. Create the Database
    const db = await serverTablesDB.create({
        databaseId: ID.unique(),
        name: 'App Database'
    });

    // 2. Create the Table with columns
    const table = await serverTablesDB.createTable({
        databaseId: db.$id,
        tableId: 'tasks',
        name: 'Tasks',
        columns: [
            { key: 'title', type: 'varchar', size: 255, required: true },
            { key: 'completed', type: 'boolean', required: true },
            { key: 'dueDate', type: 'datetime', required: false }
        ]
    });

    console.log(`Database ID: ${db.$id}`);
}

setupDatabase();
```

### 2. Client-Side: Insert a Row
Run this in your frontend application using the Web SDK. Make sure to replace `<DATABASE_ID>` with the ID generated in the previous step.

```typescript
import { Client, TablesDB, ID } from 'appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('<PROJECT_ID>');

const tablesDB = new TablesDB(client);

async function addTask() {
    // 3. Insert a row into the "tasks" table
    const task = await tablesDB.createRow({
        databaseId: '<DATABASE_ID>', 
        tableId: 'tasks',
        rowId: ID.unique(),
        data: {
            title: 'Learn Appwrite TablesDB',
            completed: false,
            dueDate: new Date().toISOString() // Appwrite expects ISO 8601 strings for datetime
        }
    });

    console.log('Task created:', task);
}

addTask();
```

### Key Takeaways:
* **`TablesDB` Class:** This is the modern API for database operations, replacing the deprecated `Databases` class.
* **Object Parameters:** All methods use the object-params calling style (e.g., `{ databaseId: '...', tableId: '...' }`).
* **Explicit String Types:** The `title` column uses the `varchar` type with a `size` limit, which stores the string inline and allows it to be fully indexed.

In Appwrite, you can query rows in a database using the `TablesDB` service and the `Query` class. The `listRows` method accepts an array of `Query` methods to filter, sort, limit, and paginate your results.

Here is how to use the `Query` class for different operations:

### 1. Filtering
Appwrite provides various methods to filter your data based on conditions. By default, multiple queries are treated as an logical `AND`.

```typescript
import { Query } from 'appwrite';

const queries = [
    Query.equal('status', 'active'),          // Exact match (can also pass an array for IN)
    Query.notEqual('category', 'archived'),   // Not equal
    Query.greaterThan('age', 18),             // Numeric comparison (<, <=, >, >= available)
    Query.startsWith('title', 'Appwrite'),    // String prefix match
    Query.search('description', 'backend'),   // Full-text search (requires a full-text index)
    Query.isNull('deletedAt')                 // Check for null values
];
```
*Note: You can also use `Query.or([...])` and `Query.and([...])` for explicit logical grouping.*

### 2. Sorting
You can sort your results by one or multiple attributes in ascending or descending order.

```typescript
const queries = [
    Query.orderDesc('$createdAt'), // Sort by creation date, newest first
    Query.orderAsc('title')        // Then sort alphabetically by title
];
```

### 3. Limiting
By default, Appwrite returns 25 rows per request. You can change this using `Query.limit()`. The maximum allowed limit is 100.

```typescript
const queries = [
    Query.limit(50) // Return up to 50 rows
];
```

### 4. Pagination
Appwrite supports two types of pagination: **Offset** and **Cursor-based**.

**Offset Pagination** (Best for small datasets or jumping to specific pages):
```typescript
const queries = [
    Query.limit(10),
    Query.offset(20) // Skips the first 20 rows (e.g., Page 3)
];
```

**Cursor Pagination** (Recommended for large datasets as it is highly performant):
```typescript
const queries = [
    Query.limit(10),
    Query.cursorAfter('last_seen_row_id') // Fetches the next 10 rows after this ID
    // Query.cursorBefore('first_seen_row_id') // Use this to go backwards
];
```

---

### Complete Example
Here is a complete example combining filtering, sorting, limiting, and cursor pagination in a single `listRows` call using the `TablesDB` service:

```typescript
import { Client, TablesDB, Query } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);

async function fetchPublishedArticles(lastId?: string) {
    const queries = [
        // 1. Filtering
        Query.equal('status', 'published'),
        Query.greaterThan('views', 100),

        // 2. Sorting
        Query.orderDesc('views'),

        // 3. Limiting
        Query.limit(10)
    ];

    // 4. Pagination
    if (lastId) {
        queries.push(Query.cursorAfter(lastId));
    }

    const results = await tablesDB.listRows({
        databaseId: '[DATABASE_ID]',
        tableId: '[TABLE_ID]',
        queries: queries
    });

    console.log(`Found ${results.total} total articles.`);
    return results.documents;
}
```

To achieve this in Appwrite, you need to combine three specific `Query` methods in the `queries` array of your database request:

1. **`Query.greaterThan('field', 100)`** to filter for values strictly greater than 100.
2. **`Query.orderDesc('field')`** to sort the results in descending order.
3. **`Query.limit(20)`** to restrict the output to a maximum of 20 results.

Here is a complete example of how to use these queries when fetching rows using the Appwrite SDK:

```typescript
import { Client, TablesDB, Query } from 'appwrite'; // or 'node-appwrite' for server-side

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);

async function fetchFilteredRows() {
    const results = await tablesDB.listRows({
        databaseId: '[DATABASE_ID]',
        tableId: '[TABLE_ID]',
        queries: [
            Query.greaterThan('score', 100), // Replace 'score' with your numeric field's key
            Query.orderDesc('score'),
            Query.limit(20)
        ]
    });

    console.log(results.documents);
}
```

*Note: Ensure that the field you are querying and sorting by has an index created in your Appwrite database table, otherwise the query will fail.*

Here is the code for an Appwrite Function in Node.js that receives a JSON body, extracts the `name` field, and returns a personalized greeting. 

Appwrite Functions use a specific signature that receives a `context` object containing `req` (request), `res` (response), `log` (logging), and `error` (error logging) objects.

```javascript
export default async ({ req, res, log, error }) => {
  // Set a default name in case one isn't provided
  let name = "World";

  if (req.body) {
    try {
      // Appwrite parses the body automatically if the Content-Type is application/json.
      // We check the type to safely handle both pre-parsed objects and raw JSON strings.
      const payload = typeof req.body === 'string' ? JSON.parse(req.body) : req.body;

      if (payload && payload.name) {
        name = payload.name;
      }
    } catch (err) {
      // Log the error to the Appwrite Console
      error(`Failed to parse JSON: ${err.message}`);

      // Return an early 400 Bad Request response
      return res.json({ 
        success: false, 
        message: "Invalid JSON body provided." 
      }, 400);
    }
  }

  // Log the successful execution
  log(`Generated greeting for: ${name}`);

  // Use res.json() to automatically send a JSON response with a 200 status code
  return res.json({
    success: true,
    message: `Hello, ${name}!`
  });
};
```

### Key Concepts Used:
1. **Function Signature:** The function exports a default asynchronous function taking a destructured context object: `({ req, res, log, error })`.
2. **`req.body`**: Contains the payload sent to the function. If the client sends the request with the `Content-Type: application/json` header, Appwrite will automatically parse it into a JavaScript object.
3. **`res.json()`**: The standard way to return a JSON response. It takes the response object as the first argument and an optional HTTP status code as the second argument (defaults to `200`).
4. **`log()` and `error()`**: Used instead of `console.log` to ensure your logs are properly captured and formatted in the Appwrite Console's execution history.

To use the Appwrite Web SDK for file management, you need to handle the file upload and preview generation. 

**Important Note on Bucket Creation:** Creating a storage bucket is an administrative action. For security reasons, it **cannot** be done via the client-side Web SDK. You must create the bucket beforehand using the Appwrite Console or the Server SDK (`node-appwrite`). 

Here is the Web SDK code to upload an image, configure its permissions, and generate a preview URL:

### 1. Install the Web SDK
```bash
npm install appwrite
```

### 2. Upload File and Get Preview

```typescript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

// Initialize the Appwrite Client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1') // e.g., https://cloud.appwrite.io/v1
    .setProject('[PROJECT_ID]');

const storage = new Storage(client);

/**
 * Uploads an image and retrieves its preview URL
 * @param {File} file - The file object from an HTML input (e.g., input.files[0])
 * @param {string} userId - The ID of the currently logged-in user
 */
async function uploadImageAndGetPreview(file: File, userId: string) {
    const BUCKET_ID = '[YOUR_BUCKET_ID]';

    try {
        // 1. Upload the file with explicit permissions
        const uploadedFile = await storage.createFile({
            bucketId: BUCKET_ID,
            fileId: ID.unique(),
            file: file,
            permissions: [
                Permission.read(Role.any()),               // Anyone can view the image
                Permission.update(Role.user(userId)),      // Only the uploader can update it
                Permission.delete(Role.user(userId))       // Only the uploader can delete it
            ]
        });

        console.log('File uploaded successfully:', uploadedFile.$id);

        // 2. Get the image preview URL
        // Note: getFilePreview is synchronous and returns a URL object, not a Promise
        const previewUrl = storage.getFilePreview({
            bucketId: BUCKET_ID,
            fileId: uploadedFile.$id,
            width: 800,   // Optional: resize width
            height: 600   // Optional: resize height
        });

        console.log('Preview URL:', previewUrl.href);
        return previewUrl.href;

    } catch (error) {
        console.error('Error uploading file:', error);
    }
}

// Example usage with an HTML file input:
// const fileInput = document.getElementById('uploader');
// await uploadImageAndGetPreview(fileInput.files[0], 'current_user_id');
```

### Key Concepts Used:
* **`ID.unique()`**: Automatically generates a unique identifier for your uploaded file.
* **Permissions**: By default, Appwrite denies all access. We use `Permission.read(Role.any())` to make the image publicly visible (necessary if you want to display the preview URL on a public website) while restricting `update` and `delete` actions strictly to the user who uploaded it.
* **`getFilePreview()`**: This method returns a `URL` object immediately (no `await` needed). It is highly optimized for images and allows you to pass optional parameters like `width`, `height`, and `quality` to crop or compress the image on the fly.

To send a push notification to all users subscribed to a topic in Appwrite, you need to use the **Messaging** service. 

Here is what must be configured first, followed by the steps to send the notification.

### What Must Be Configured First?

Before you can send any push notifications, the following prerequisites must be met:

1. **Configure a Push Provider:** In the Appwrite Console, navigate to the **Messaging** section and configure a Push Notification provider. You will need to set up **FCM** (Firebase Cloud Messaging) for Android/Web or **APNs** (Apple Push Notification service) for iOS by providing your provider credentials (keys/certificates).
2. **Create a Topic:** You must create a Topic (e.g., `announcements` or `promotions`) to act as the broadcast channel.
3. **Register Device Targets:** Your client applications (iOS, Android, or Web) must request push notification permissions from the user, retrieve the device token from the OS, and register that token as a **Target** on the user's Appwrite account.
4. **Add Subscribers:** The users (or their specific device targets) must be added as **Subscribers** to your created Topic.

---

### Steps to Send the Push Notification

Once your provider is configured and users are subscribed to a topic, you can send a push notification using a Server SDK (like Node.js) or the Appwrite CLI. 

*(Note: Sending messages requires an API Key with `messaging.write` scopes; it cannot be done directly from the client SDK).*

#### Option 1: Using the Server SDK (Node.js / TypeScript)

Initialize the `Messaging` service using your admin client and call the `createPush` method, passing your Topic ID in the `topics` array.

```typescript
import { Client, Messaging, ID } from 'node-appwrite';

// 1. Initialize the Server Client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('<PROJECT_ID>')
    .setKey('<YOUR_API_KEY>');

const messaging = new Messaging(client);

// 2. Send the Push Notification
async function sendTopicPush() {
    const message = await messaging.createPush({
        messageId: ID.unique(),
        title: 'New Feature Alert!',
        body: 'Check out the new updates in the app.',
        topics: ['<TOPIC_ID>'], // Targets all subscribers of this topic
        // Optional fields:
        // data: { link: '/new-feature' },
        // scheduledAt: '2024-12-31T23:59:59.000Z'
    });

    console.log('Message sent:', message.$id);
}
```

#### Option 2: Using the Appwrite CLI

If you are managing your project via the command line or a CI/CD pipeline, you can trigger the push notification using the `messaging create-push` command:

```bash
appwrite messaging create-push \
    --message-id "unique()" \
    --title "New Feature Alert!" \
    --body "Check out the new updates in the app." \
    --topics "<TOPIC_ID>"
```

Here is how you can use the Appwrite Web SDK to subscribe to both table row changes and file uploads simultaneously. 

You can pass an array of channels to the `realtime.subscribe()` method and then inspect the `response.events` array to determine which type of resource triggered the event.

```typescript
import { Client, Realtime, Channel } from 'appwrite';

// 1. Initialize the Appwrite Client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Replace with your endpoint
    .setProject('<YOUR_PROJECT_ID>');            // Replace with your project ID

const realtime = new Realtime(client);

const databaseId = '<YOUR_DATABASE_ID>';
const tableId = '<YOUR_TABLE_ID>';
const bucketId = '<YOUR_BUCKET_ID>';

// 2. Subscribe to multiple channels simultaneously
const subscription = realtime.subscribe([
    Channel.tablesdb(databaseId).table(tableId).row(), // Listen to all row changes in a table
    Channel.bucket(bucketId).file()                    // Listen to all file changes in a bucket
], (response) => {

    // response.events contains an array of event strings (e.g., 'tablesdb.*.tables.*.rows.*.create')
    // response.payload contains the affected resource (the row data or file metadata)
    const event = response.events[0]; 

    // 3. Handle Table Row Events
    if (event.includes('tablesdb') && event.includes('rows')) {
        console.log('Table row event detected!');

        if (event.includes('.create')) {
            console.log('New row created:', response.payload);
        } else if (event.includes('.update')) {
            console.log('Row updated:', response.payload);
        } else if (event.includes('.delete')) {
            console.log('Row deleted:', response.payload);
        }
    } 

    // 4. Handle File Upload/Storage Events
    else if (event.includes('buckets') && event.includes('files')) {
        console.log('File event detected!');

        if (event.includes('.create')) {
            console.log('New file uploaded:', response.payload);
        } else if (event.includes('.update')) {
            console.log('File metadata updated:', response.payload);
        } else if (event.includes('.delete')) {
            console.log('File deleted:', response.payload);
        }
    }
});

// When you no longer need to listen to these events, you can close the subscription:
// subscription();
```

### How it works:
1. **`Channel.tablesdb(...).table(...).row()`**: Subscribes to all row creations, updates, and deletions in the specified table.
2. **`Channel.bucket(...).file()`**: Subscribes to all file uploads, updates, and deletions in the specified storage bucket.
3. **`response.events`**: Appwrite returns a wildcard-formatted string detailing exactly what happened (e.g., `buckets.[ID].files.[ID].create`). By checking if the event string includes `tablesdb` or `buckets`, you can easily route the payload to the correct handler logic.

To listen to multiple channels in a single call, you pass an array of channel strings to the `realtime.subscribe()` method. 

Here is the single call using the SDK's `Channel` helper:

```typescript
import { Channel } from 'appwrite';

const subscription = realtime.subscribe([
    Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
    Channel.bucket('[BUCKET_ID]').file()
], (response) => {
    console.log('Event received:', response.events);
    console.log('Payload:', response.payload);
});
```

### Exact Channel Strings
If you prefer to use the raw strings instead of the `Channel` helper, the exact channel strings are:

1. **TablesDB Table Rows:** `tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows`
2. **Storage Bucket Files:** `buckets.[BUCKET_ID].files`

*(Note: Replace `[DATABASE_ID]`, `[TABLE_ID]`, and `[BUCKET_ID]` with your actual Appwrite resource IDs).*

```bash
npm install appwrite
```

```ts
// appwrite.ts
import { Client, Account, ID, AppwriteException } from "appwrite";

// 1. Set up the Appwrite client
const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1") // or your self-hosted endpoint
  .setProject("<PROJECT_ID>");

export const account = new Account(client);

// 2. Sign up with email/password
export async function signUp(email: string, password: string, name?: string) {
  try {
    const user = await account.create({
      userId: ID.unique(),
      email,
      password,
      name,
    });

    // Optional: log the user in immediately after signup
    const session = await account.createEmailPasswordSession({
      email,
      password,
    });

    return { user, session };
  } catch (error) {
    if (error instanceof AppwriteException) {
      console.error(error.message);
    }
    throw error;
  }
}

// 3. Log in with email/password
export async function login(email: string, password: string) {
  try {
    const session = await account.createEmailPasswordSession({
      email,
      password,
    });

    return session;
  } catch (error) {
    if (error instanceof AppwriteException) {
      console.error(error.message);
    }
    throw error;
  }
}

// Optional: get the currently logged-in user
export async function getCurrentUser() {
  return await account.get();
}

// Optional: log out
export async function logout() {
  return await account.deleteSession({
    sessionId: "current",
  });
}
```

Example usage:

```ts
import { signUp, login, getCurrentUser, logout } from "./appwrite";

// Signup
await signUp("user@example.com", "password123", "Jane Doe");

// Login
await login("user@example.com", "password123");

// Get current authenticated user
const user = await getCurrentUser();
console.log(user);

// Logout
await logout();
```

Replace:

```ts
"<REGION>"
"<PROJECT_ID>"
```

with your Appwrite Cloud region and project ID.

You can’t safely create databases/tables from a public browser app with the Web SDK because schema creation is an admin/server-side operation. Use `TablesDB` with the current API from a trusted environment, such as an Appwrite Function or backend using `node-appwrite`.

```ts
import { Client, TablesDB, ID, Permission, Role } from 'node-appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>')
  .setKey('<APPWRITE_API_KEY>');

const tablesDB = new TablesDB(client);

async function setupTasksTable() {
  // 1. Create database
  const database = await tablesDB.create({
    databaseId: ID.unique(),
    name: 'Tasks Database',
  });

  // 2. Create "tasks" table with columns
  const table = await tablesDB.createTable({
    databaseId: database.$id,
    tableId: 'tasks',
    name: 'Tasks',
    columns: [
      {
        key: 'title',
        type: 'varchar',
        size: 255,
        required: true,
      },
      {
        key: 'completed',
        type: 'boolean',
        required: true,
      },
      {
        key: 'dueDate',
        type: 'datetime',
        required: false,
      },
    ],
    permissions: [
      Permission.read(Role.any()),
      Permission.create(Role.users()),
    ],
  });

  // 3. Insert a row
  const task = await tablesDB.createRow({
    databaseId: database.$id,
    tableId: table.$id,
    rowId: ID.unique(),
    data: {
      title: 'Finish Appwrite setup',
      completed: false,
      dueDate: new Date('2026-01-15T12:00:00.000Z').toISOString(),
    },
    permissions: [
      Permission.read(Role.any()),
      Permission.update(Role.users()),
      Permission.delete(Role.users()),
    ],
  });

  console.log({ database, table, task });
}

setupTasksTable().catch(console.error);
```

For a browser app using the Web SDK, create the database/table ahead of time on the server, then only insert rows from the client:

```ts
import { Client, TablesDB, ID } from 'appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>');

const tablesDB = new TablesDB(client);

await tablesDB.createRow({
  databaseId: '<DATABASE_ID>',
  tableId: 'tasks',
  rowId: ID.unique(),
  data: {
    title: 'Finish Appwrite setup',
    completed: false,
    dueDate: new Date('2026-01-15T12:00:00.000Z').toISOString(),
  },
});

Use `TablesDB.listRows()` and pass an array of `Query` helpers in the `queries` option. Each `Query.*()` call creates one query condition.

```ts
import { Client, TablesDB, Query } from 'appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);

const result = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.equal('status', 'active'),
    Query.limit(10),
  ],
});

console.log(result.total);
console.log(result.rows); // In some older SDK/model typings this may be `documents`
```

## Filtering rows

Queries are combined with `AND` by default.

```ts
const activeTodos = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.equal('status', 'active'),
    Query.equal('done', false),
  ],
});
```

More filter examples:

```ts
queries: [
  Query.equal('category', 'work'),              // category == "work"
  Query.notEqual('status', 'archived'),         // status != "archived"
  Query.greaterThan('priority', 2),             // priority > 2
  Query.lessThanEqual('price', 100),            // price <= 100
  Query.between('age', 18, 65),                 // 18 <= age <= 65
  Query.isNull('deletedAt'),                    // deletedAt is null
  Query.isNotNull('publishedAt'),               // publishedAt is not null
  Query.startsWith('title', 'Appwrite'),        // title starts with "Appwrite"
  Query.contains('tags', 'backend'),            // array/string contains value
]
```

You can pass an array to `Query.equal()` for an `IN`-style query:

```ts
const posts = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.equal('status', ['draft', 'published']),
  ],
});
```

Full-text search:

```ts
const searchResults = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.search('content', 'serverless functions'),
  ],
});
```

`Query.search()` requires a full-text index on the column.

## Sorting rows

Use `Query.orderAsc()` or `Query.orderDesc()`.

```ts
const newestPosts = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.equal('status', 'published'),
    Query.orderDesc('$createdAt'),
  ],
});
```

Sort by a custom column:

```ts
const topProducts = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.orderDesc('rating'),
    Query.orderAsc('name'),
  ],
});
```

## Limiting results

Use `Query.limit()` to control how many rows are returned.

```ts
const firstTen = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.limit(10),
  ],
});
```

Default limit is usually `25`; maximum is `100`.

## Offset pagination

Offset pagination skips a number of rows.

```ts
const page = 3;
const limit = 20;

const result = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.orderDesc('$createdAt'),
    Query.limit(limit),
    Query.offset((page - 1) * limit),
  ],
});
```

This is simple, but for large datasets cursor pagination is preferred.

## Cursor pagination

Cursor pagination uses the last or first row ID from the previous page.

```ts
const firstPage = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.orderDesc('$createdAt'),
    Query.limit(20),
  ],
});

const lastRow = firstPage.rows[firstPage.rows.length - 1];

const secondPage = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.orderDesc('$createdAt'),
    Query.limit(20),
    Query.cursorAfter(lastRow.$id),
  ],
});
```

To go backward:

```ts
const previousPage = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.orderDesc('$createdAt'),
    Query.limit(20),
    Query.cursorBefore(firstRow.$id),
  ],
});
```

## Combining conditions with OR

By default, query conditions are `AND`ed together. Use `Query.or()` when needed.

```ts
const urgentOrHighPriority = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: [
    Query.or([
      Query.equal('urgent', true),
      Query.greaterThanEqual('priority', 8),
    ]),
    Query.orderDesc('$createdAt'),
    Query.limit(25),
  ],
});
```

## Complete example

```ts
const result = await tablesDB.listRows({
  databaseId: 'main',
  tableId: 'tasks',
  queries: [
    Query.equal('status', 'open'),
    Query.greaterThanEqual('priority', 3),
    Query.orderDesc('$createdAt'),
    Query.limit(20),
  ],
});

for (const row of result.rows) {
  console.log(row.$id, row.title, row.priority);
}
```

In short: pass `Query` helpers to `listRows()`. Use filters to narrow results, `orderAsc`/`orderDesc` to sort, `limit` to cap results, and `offset` or cursor queries for pagination.

```js
// src/main.js

export default async ({ req, res, log, error }) => {
  const body = req.bodyJson;

  if (!body || typeof body.name !== 'string' || body.name.trim() === '') {
    return res.json(
      {
        error: 'Missing or invalid "name" field',
      },
      400
    );
  }

  const name = body.name.trim();

  return res.json({
    greeting: `Hello, ${name}!`,
  });
};
```

Example JSON request body:

```json
{
  "name": "Alex"
}
```

Example response:

```json
{
  "greeting": "Hello, Alex!"
}
```

You can upload files and get preview URLs with the Appwrite **Web SDK**, but creating a bucket is an **admin/server-side operation**. Do **not** create buckets from browser code or expose an API key in the frontend.

Below is a safe setup:

---

## 1. Server-side bucket creation

Use `node-appwrite` in a backend script, server route, or Appwrite Function.

```ts
// create-bucket.ts
import { Client, Storage, ID, Permission, Role } from 'node-appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>')
  .setKey(process.env.APPWRITE_API_KEY!);

const storage = new Storage(client);

const bucket = await storage.createBucket({
  bucketId: 'images',
  name: 'Images',
  permissions: [
    // Anyone can read files from this bucket
    Permission.read(Role.any()),

    // Only authenticated users can upload files
    Permission.create(Role.users()),
  ],
  fileSecurity: true,
  enabled: true,
  maximumFileSize: 10 * 1024 * 1024, // 10 MB
  allowedFileExtensions: ['jpg', 'jpeg', 'png', 'webp', 'gif'],
  compression: 'gzip',
  encryption: true,
  antivirus: true,
});

console.log('Bucket created:', bucket);
```

Your API key needs the appropriate Storage/Buckets scope.

---

## 2. Browser upload and preview URL with Appwrite Web SDK

```ts
// appwrite-storage.ts
import { Client, Storage, ID, Permission, Role } from 'appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>');

const storage = new Storage(client);

const BUCKET_ID = 'images';

export async function uploadImageAndGetPreview(file: File) {
  if (!file.type.startsWith('image/')) {
    throw new Error('Only image files are allowed.');
  }

  const uploadedFile = await storage.createFile({
    bucketId: BUCKET_ID,
    fileId: ID.unique(),
    file,
    permissions: [
      // Publicly readable, required if the preview should be visible without login
      Permission.read(Role.any()),

      // The signed-in user who uploads can update/delete their own file
      Permission.update(Role.users()),
      Permission.delete(Role.users()),
    ],
  });

  const previewUrl = storage.getFilePreview({
    bucketId: BUCKET_ID,
    fileId: uploadedFile.$id,
    width: 600,
    height: 600,
    quality: 90,
  });

  return {
    file: uploadedFile,
    previewUrl,
  };
}
```

---

## 3. Example usage with an `<input type="file">`

```ts
import { uploadImageAndGetPreview } from './appwrite-storage';

const input = document.querySelector<HTMLInputElement>('#image-input')!;
const img = document.querySelector<HTMLImageElement>('#preview')!;

input.addEventListener('change', async () => {
  const file = input.files?.[0];
  if (!file) return;

  try {
    const { file: uploadedFile, previewUrl } = await uploadImageAndGetPreview(file);

    console.log('Uploaded file:', uploadedFile);
    console.log('Preview URL:', previewUrl);

    img.src = previewUrl.toString();
  } catch (error) {
    console.error('Upload failed:', error);
  }
});
```

```html
<input id="image-input" type="file" accept="image/*" />
<img id="preview" alt="Image preview" />
```

---

If files should only be visible to logged-in users, replace:

```ts
Permission.read(Role.any())
```

with:

```ts
Permission.read(Role.users())
```

To set up push notifications with **Appwrite Messaging**, the flow is:

1. **Create a push provider**
   - In the Appwrite Console, go to **Messaging → Providers → Create provider**.
   - For push notifications, Appwrite supports:
     - **Firebase Cloud Messaging (FCM)** — commonly used for Android, web, and Firebase-based iOS apps.
     - **Apple Push Notification service (APNs)** — native Apple push notifications for iOS/macOS.
   - Configure the provider with the required credentials from Firebase or Apple.

2. **Register a user device as a push target**
   - Your app must first get the device push token from FCM or APNs.
   - Then register that token with Appwrite, usually from the authenticated client:

```ts
import { Client, Account, ID } from 'appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>');

const account = new Account(client);

// deviceToken comes from FCM or APNs
await account.createPushTarget({
  targetId: ID.unique(),
  identifier: deviceToken,
  providerId: '<PROVIDER_ID>',
});
```

3. **Create a topic and subscribe targets**
   - Topics are groups of subscribers.
   - Use a trusted backend or Appwrite Function with an API key.

```ts
import { Client, Messaging, ID } from 'node-appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject(process.env.APPWRITE_PROJECT_ID)
  .setKey(process.env.APPWRITE_API_KEY);

const messaging = new Messaging(client);

// Create topic
await messaging.createTopic({
  topicId: 'news',
  name: 'News Updates',
});

// Subscribe a registered push target to the topic
await messaging.createSubscriber({
  topicId: 'news',
  subscriberId: ID.unique(),
  targetId: '<TARGET_ID>',
});
```

4. **Send a push notification to the topic**

```ts
await messaging.createPush({
  messageId: ID.unique(),
  title: 'Breaking News',
  body: 'A new article is available.',
  topics: ['news'],
  data: {
    articleId: '123',
  },
});
```

The `topics` array contains topic IDs, not topic names. Appwrite will send the push notification to all push targets subscribed to that topic.

Appwrite Messaging targets **delivery targets**, not just raw addresses. A **target** is a concrete destination for a user, such as an email address, phone number, or push token. Messages can be addressed in three ways:

1. **Users** — send to one or more Appwrite user IDs. Appwrite resolves the user to their compatible targets.
2. **Topics** — send to all targets subscribed to a Messaging topic.
3. **Targets** — send directly to specific target IDs, useful for one device, one phone number, or one email target.

You can use any combination of `users`, `topics`, and `targets` when creating an email, SMS, or push message. Appwrite expands topics and users into targets for the relevant message type.

Example using the Node SDK:

```ts
import { Client, Messaging, ID } from 'node-appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>')
  .setKey('<API_KEY>');

const messaging = new Messaging(client);
```

### Send to specific users

```ts
await messaging.createEmail({
  messageId: ID.unique(),
  subject: 'Welcome!',
  content: 'Thanks for joining.',
  users: ['userId1', 'userId2'],
});
```

For push:

```ts
await messaging.createPush({
  messageId: ID.unique(),
  title: 'New update',
  body: 'Check out what changed.',
  users: ['userId1'],
});
```

### Send to a topic

First, targets must be subscribed to the topic:

```ts
await messaging.createSubscriber({
  topicId: 'announcements',
  subscriberId: ID.unique(),
  targetId: 'targetId1',
});
```

Then send to the topic:

```ts
await messaging.createPush({
  messageId: ID.unique(),
  title: 'Announcement',
  body: 'We launched a new feature.',
  topics: ['announcements'],
});
```

### Send to individual targets

Use this when you want to address a specific destination, such as one push device token or one phone/email target:

```ts
await messaging.createSms({
  messageId: ID.unique(),
  content: 'Your verification code is 123456',
  targets: ['targetId1'],
});
```

