Here's a complete example using the **Appwrite Web SDK** to create a bucket, upload an image with permissions, and generate a preview URL.

```typescript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

// 1. Initialize the client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const storage = new Storage(client);

// 2. Create a bucket with permissions
// Note: Bucket creation usually requires admin/server-side privileges.
// In production, you may create the bucket once via the Console or server SDK.
async function createImageBucket() {
    const bucket = await storage.createBucket({
        bucketId: ID.unique(),
        name: 'Image Uploads',
        permissions: [
            Permission.read(Role.any()),      // Anyone can view files
            Permission.create(Role.users())   // Only authenticated users can upload
        ],
        fileSecurity: true  // Enable file-level permissions (optional)
    });
    return bucket.$id;
}

// 3. Upload a file with file-level permissions
async function uploadImage(bucketId: string, file: File) {
    const uploadedFile = await storage.createFile({
        bucketId: bucketId,
        fileId: ID.unique(),
        file: file,
        permissions: [
            Permission.read(Role.any()),                 // Public read access
            Permission.update(Role.user('[USER_ID]')),   // Owner can update
            Permission.delete(Role.user('[USER_ID]'))    // Owner can delete
        ]
    });
    return uploadedFile.$id;
}

// 4. Get an image preview URL
// Returns a string URL directly (not a Promise)
function getImagePreview(bucketId: string, fileId: string): string {
    const previewUrl = storage.getFilePreview({
        bucketId: bucketId,
        fileId: fileId,
        width: 400,
        height: 400,
        quality: 80,
        gravity: 'center'
    });
    return previewUrl;
}

// 5. Usage with a file input
async function handleFileSelect(event: Event) {
    const input = event.target as HTMLInputElement;
    if (!input.files || input.files.length === 0) return;

    try {
        // Create bucket (or use an existing bucket ID)
        const bucketId = await createImageBucket();

        // Upload the selected image
        const fileId = await uploadImage(bucketId, input.files[0]);

        // Get preview URL
        const previewUrl = getImagePreview(bucketId, fileId);

        console.log('Preview URL:', previewUrl);

        // Use it in your UI
        const img = document.getElementById('preview') as HTMLImageElement;
        img.src = previewUrl;

    } catch (error) {
        console.error('Storage operation failed:', error);
    }
}

// Attach to a file input in your HTML
// <input type="file" id="file-input" accept="image/*" />
document.getElementById('file-input')?.addEventListener('change', handleFileSelect);
```

### Key details

| Step | Notes |
|------|-------|
| **Bucket creation** | Usually requires admin privileges. The snippet above assumes the client has rights; otherwise create the bucket in the Appwrite Console or use `node-appwrite`. |
| **Permissions** | `Role.any()` makes a resource public. `Role.user('[USER_ID]')` restricts to a specific user. `Role.users()` targets all authenticated users. |
| **File upload** | Pass the native `File` object from a file input. On server-side you would use `InputFile.fromPath()` instead. |
| **Preview** | `getFilePreview()` returns a URL string immediately (it does not return a Promise). It only works for image files. |

