// ============================================
// 2. Create a bucket (requires appropriate permissions)
//    Note: In production, prefer creating buckets via the Appwrite Console
//    or server-side SDK (node-appwrite) for security.
// ============================================
async function createBucket() {
  try {
    const bucket = await storage.createBucket({
      bucketId: ID.unique(),
      name: 'Images Bucket',
      permissions: [
        Permission.read(Role.any()),           // Anyone can read files
        Permission.create(Role.users()),       // Only authenticated users can upload
        Permission.update(Role.user('[USER_ID]')), // Example: specific user can update
        Permission.delete(Role.user('[USER_ID]')), // Example: specific user can delete
      ],
      fileSecurity: true,           // Enforce per-file permissions
      maximumFileSize: 10 * 1024 * 1024, // 10MB limit
      allowedFileExtensions: ['jpg', 'jpeg', 'png', 'gif', 'webp'],
    });

    console.log('Bucket created:', bucket.$id);
    return bucket.$id;
  } catch (error) {
    console.error('Bucket creation failed:', error);
    throw error;
  }
}

// ============================================
// 3. Upload a file with permissions
// ============================================
async function uploadFile(bucketId: string, file: File) {
  try {
    const uploadedFile = await storage.createFile({
      bucketId,
      fileId: ID.unique(),
      file, // Browser File object (from <input type="file">)
      permissions: [
        Permission.read(Role.any()),           // Public preview
        Permission.update(Role.user('[USER_ID]')), // Owner can update
        Permission.delete(Role.user('[USER_ID]')), // Owner can delete
      ],
    });

    console.log('File uploaded:', uploadedFile.$id);
    return uploadedFile;
  } catch (error) {
    console.error('Upload failed:', error);
    throw error;
  }
}

// ============================================
// 4. Get preview URL for an image
// ============================================
function getImagePreviewUrl(bucketId: string, fileId: string) {
  // Returns a URL string you can use directly in <img src="...">
  const previewUrl = storage.getFilePreview({
    bucketId,
    fileId,
    width: 400,
    height: 400,
    quality: 80,
    // gravity: 'center', // optional
  });

  return previewUrl; // Use as string or with .href if needed
}

// ============================================
// Usage example (e.g. in a React component or vanilla JS)
// ============================================
async function handleImageUpload(fileInput: HTMLInputElement) {
  if (!fileInput.files?.[0]) return;

  const bucketId = await createBucket();           // or use existing bucket ID
  const uploaded = await uploadFile(bucketId, fileInput.files[0]);
  const previewUrl = getImagePreviewUrl(bucketId, uploaded.$id);

  // Use the preview
  const img = document.createElement('img');
  img.src = previewUrl;
  document.body.appendChild(img);

  console.log('Preview URL:', previewUrl);
}
```

### Key Notes
- **Permissions**: Use `Permission` + `Role` helpers. `Role.any()` makes files publicly readable (common for images). Avoid granting `write`/`update`/`delete` to `Role.any()`.
- **Bucket creation**: Usually done once via the Appwrite Console (Storage → Buckets). Client-side creation requires the authenticated user to have `buckets.create` scope.
- **File input**: Pass a real `File` object from `<input type="file">`.
- **Error handling**: Wrap calls in `try/catch` and check for `AppwriteException`.
- **Security**: Never expose an API key in the browser. Use sessions for authenticated users.

This follows the official Appwrite TypeScript/Web SDK patterns for storage operations.

**Appwrite Messaging** (for emails, SMS, and push notifications) handles targeting through three primary, combinable mechanisms when creating a message: `users`, `topics`, and `targets`. These are passed as arrays of IDs to the `createEmail`, `createSms`, or `createPush` methods (available via the server SDKs, REST API, or CLI).

### Key Targeting Concepts
- **Users**: Targets specific Appwrite user accounts by their `$id`. The platform automatically resolves and delivers the message to all registered contact methods (email, phone) or push devices associated with those users. Ideal for personalized or user-specific notifications.
- **Topics**: Broadcasts to groups of users who have explicitly subscribed. Topics act as channels (e.g., "news", "promotions"). Subscribers are managed separately via the Topics API. This is efficient for segmented or opt-in group messaging.
- **Individual Targets**: Provides the most granular control. Targets represent specific delivery endpoints:
  - For push: Registered device tokens (FCM, APNS, etc.).
  - For email/SMS: Specific email addresses or phone numbers (often tied to users but addressable directly).
  Targets are created automatically (e.g., during push registration) or via the Targets API. Use this for direct device-level or one-off sends.

You can combine all three in a single message (e.g., send to specific users *and* a topic). Appwrite deduplicates recipients. Messages can also be sent as drafts for later scheduling or review.

### Sending Messages (Examples)
Use the server-side SDK (e.g., `node-appwrite`) or equivalent in other languages. Always use an API key with appropriate scopes.

```typescript
import { Client, Messaging, ID } from 'node-appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>')
  .setKey('<API_KEY>');

const messaging = new Messaging(client);

// Send an email to specific users + a topic
const emailMessage = await messaging.createEmail({
  messageId: ID.unique(),
  subject: 'Welcome!',
  content: '<p>Hello from Appwrite</p>',
  users: ['user_abc123', 'user_def456'],  // Specific users
  topics: ['topic_news'],                  // Subscribers to this topic
  targets: ['target_xyz789'],              // Individual target (e.g., specific email or device)
  draft: false,                            // Set true to save as draft
  // Additional options: html, attachments, etc.
});

// Send a push notification to a topic + individual targets
const pushMessage = await messaging.createPush({
  messageId: ID.unique(),
  title: 'New Update',
  body: 'Check out the latest features',
  topics: ['topic_updates'],
  targets: ['target_device1', 'target_device2'],
  // data: { custom: 'payload' }, // for deep linking
});

// Send an SMS to specific users
const smsMessage = await messaging.createSms({
  messageId: ID.unique(),
  content: 'Your verification code is 123456',
  users: ['user_abc123'],
});
```

### Managing Topics and Subscribers
- Create topics: `messaging.createTopic({ topicId: ID.unique(), name: 'News' })`
- Subscribe a user (or target) to a topic: `messaging.createSubscriber({ topicId: '...', subscriberId: ID.unique(), targetId: '...' })`
- List subscribers: `messaging.listSubscribers({ topicId: '...' })`
- Remove: `messaging.deleteSubscriber(...)`

### Additional Notes
- **CLI equivalents** (for scripting/CI): `appwrite messaging create-email --users '["id1"]' --topics '["topic1"]' --targets '["t1"]' ...` (similar flags for SMS/push).
- Targets are listed/retrieved via the Targets API (`listTargets`, etc.) for push registration flows.
- Delivery status, logs, and retries are available via `getMessage` and related endpoints.
- Permissions and rate limits apply; use server-side keys for admin sends.
- For client-side, users can only subscribe/unsubscribe to topics they have access to (via their session).

This system allows flexible, scalable targeting without managing recipient lists manually. For full parameter details, see the Messaging section in the Appwrite docs or SDK references.

**Appwrite Web SDK (TypeScript/JavaScript) – Simultaneous Realtime Subscriptions**

```typescript
import { Client, Realtime, Channel } from 'appwrite';

// 1. Initialize the client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1') // e.g. https://cloud.appwrite.io/v1
    .setProject('<YOUR_PROJECT_ID>');

// 2. Create Realtime instance
const realtime = new Realtime(client);

// 3. Define your resource IDs
const DATABASE_ID = '<YOUR_DATABASE_ID>';
const TABLE_ID    = '<YOUR_TABLE_ID>';
const BUCKET_ID   = '<YOUR_BUCKET_ID>';

// 4. Subscribe to both channels at the same time
const subscription = await realtime.subscribe(
    [
        // All row changes in the table
        Channel.tablesdb(DATABASE_ID).table(TABLE_ID).row(),

        // All file changes in the bucket (create = upload)
        Channel.bucket(BUCKET_ID).file()
    ],
    (response) => {
        const { events, payload, channels } = response;

        console.log('Realtime event received:', events);

        // Differentiate by event type
        const isRowEvent = events.some(e => e.includes('.rows.'));
        const isFileEvent = events.some(e => e.includes('.files.'));

        if (isRowEvent) {
            // Handle table row changes (create, update, delete)
            const eventType = events.find(e => e.includes('.rows.'))?.split('.').pop(); // e.g. "create", "update", "delete"

            console.log(`[TABLE ROW] ${eventType?.toUpperCase()}:`, payload);

            switch (eventType) {
                case 'create':
                    // New row created
                    handleNewRow(payload);
                    break;
                case 'update':
                    // Row updated
                    handleRowUpdate(payload);
                    break;
                case 'delete':
                    // Row deleted
                    handleRowDelete(payload);
                    break;
            }
        } 
        else if (isFileEvent) {
            // Handle file events (upload = create)
            const eventType = events.find(e => e.includes('.files.'))?.split('.').pop();

            console.log(`[FILE] ${eventType?.toUpperCase()}:`, payload);

            if (eventType === 'create') {
                // File uploaded
                handleFileUpload(payload);
            } else if (eventType === 'update') {
                handleFileUpdate(payload);
            } else if (eventType === 'delete') {
                handleFileDelete(payload);
            }
        }
    }
);

// 5. Example handler functions
function handleNewRow(row: any) {
    console.log('New row inserted:', row.$id, row);
    // e.g. update UI, trigger notification, etc.
}

function handleRowUpdate(row: any) {
    console.log('Row updated:', row.$id);
}

function handleRowDelete(row: any) {
    console.log('Row deleted:', row.$id);
}

function handleFileUpload(file: any) {
    console.log('File uploaded:', file.$id, file.name, file.mimeType);
    // e.g. show preview, update file list
}

function handleFileUpdate(file: any) {
    console.log('File updated:', file.$id);
}

function handleFileDelete(file: any) {
    console.log('File deleted:', file.$id);
}

// 6. Cleanup when no longer needed (e.g. on component unmount)
async function unsubscribe() {
    await subscription.close();
    console.log('Realtime subscription closed');
}
```

### Key Points
- **Simultaneous subscription**: Pass an array of channels to `realtime.subscribe()`.
- **Event differentiation**: Use `response.events` (contains strings like `tablesdb.*.tables.*.rows.*.create` or `buckets.*.files.*.create`).
- **Payload**: `response.payload` contains the full row (`Models.Document`) or file (`Models.File`) object.
- **Unsubscribe**: Always call `subscription.close()` to avoid memory leaks.
- **Permissions**: The user must have `read` permission on the table rows and bucket files for realtime events to be delivered.

Replace the placeholder IDs with your actual Appwrite resource IDs. This pattern works in any browser environment (plain JS, React, Vue, etc.).

**Single `realtime.subscribe()` call (TypeScript SDK):**

```ts
import { Client, Realtime, Channel } from 'appwrite';

const client = new Client().setEndpoint('...').setProject('...');
const realtime = new Realtime(client);

const subscription = realtime.subscribe([
  Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),   // all rows
  Channel.bucket('[BUCKET_ID]').file()                           // all files
], (response) => {
  console.log(response.events, response.payload);
});
```

**Exact channel strings** (what the `Channel` helpers produce):

- `tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows`
- `buckets.[BUCKET_ID].files`

You can also pass the raw strings directly:

```ts
realtime.subscribe([
  'tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows',
  'buckets.[BUCKET_ID].files'
], callback);
```

These two channels together let one subscription receive events for both TablesDB row changes and Storage file changes.

Here's a complete implementation of email/password signup and login using the Appwrite Web SDK:

## Installation

```bash
npm install appwrite
```

## Setup the Client

```typescript
// appwrite.ts
import { Client, Account, ID } from 'appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1') // your API endpoint
    .setProject('[PROJECT_ID]');                          // your project ID

export const account = new Account(client);
export { ID };
```

## Signup (Create Account + Session)

```typescript
import { account, ID } from './appwrite';
import { AppwriteException } from 'appwrite';

async function signUp(email: string, password: string, name: string) {
    try {
        // 1. Create the user account
        await account.create({
            userId: ID.unique(),
            email,
            password,
            name,
        });

        // 2. Immediately log the new user in by creating a session
        const session = await account.createEmailPasswordSession({
            email,
            password,
        });

        // 3. Fetch the current user
        const user = await account.get();
        console.log('Signed up & logged in as:', user.name);

        return user;
    } catch (err) {
        if (err instanceof AppwriteException) {
            // e.g. 409 = a user with this email already exists
            console.error(`${err.code}: ${err.message}`);
        }
        throw err;
    }
}
```

## Login (Create Session)

```typescript
import { account } from './appwrite';
import { AppwriteException } from 'appwrite';

async function login(email: string, password: string) {
    try {
        const session = await account.createEmailPasswordSession({
            email,
            password,
        });

        const user = await account.get();
        console.log('Logged in as:', user.name);

        return user;
    } catch (err) {
        if (err instanceof AppwriteException) {
            // e.g. 401 = invalid credentials
            console.error(`${err.code}: ${err.message}`);
        }
        throw err;
    }
}
```

## Logout

```typescript
import { account } from './appwrite';

async function logout() {
    // 'current' deletes the active session
    await account.deleteSession({ sessionId: 'current' });
}
```

## Key Points

- **`account.create()`** registers the user but does **not** log them in — you must create a session separately. That's why the signup flow chains `createEmailPasswordSession()` afterward.
- **`createEmailPasswordSession()`** stores the session in a cookie automatically (browser SDK), so subsequent requests are authenticated.
- **`account.get()`** retrieves the currently authenticated user — use it on page load to check if a session already exists.
- Passwords must be at least **8 characters** by default.
- `ID.unique()` lets Appwrite generate a unique user ID; you can also pass your own.
- Wrap calls in try/catch for `AppwriteException` to handle common cases like `409` (email already exists) and `401` (invalid credentials).

Here's a comprehensive explanation of how Appwrite sessions work.

## What Is a Session?

A session represents an authenticated login for a user. When a user logs in, Appwrite issues a session object (`Models.Session`) containing a **secret** and an **expiry**. This secret is what authenticates subsequent requests on behalf of that user.

## How Sessions Are Created

Sessions are created through various authentication methods on the `Account` service:

```typescript
const account = new Account(client);

// 1. Email + Password
const session = await account.createEmailPasswordSession({
    email: 'user@example.com',
    password: 'password123'
});

// 2. OAuth2 (browser — handles redirect automatically)
account.createOAuth2Session({
    provider: OAuthProvider.Github,
    success: 'https://example.com/success',
    failure: 'https://example.com/fail'
});

// 3. Token-based (OAuth on React Native/SSR, magic URL, phone OTP, etc.)
//    First obtain a userId + secret, then exchange them:
await account.createSession({ userId, secret });

// 4. Anonymous session (guest users)
// await account.createAnonymousSession();
```

There are several other token-based flows too (magic URL login, phone/SMS OTP, etc.) — they all follow the pattern of getting a `userId` + `secret`, then calling `createSession()`.

## How Sessions Are Managed

**Client-side (Web/React Native):** The SDK automatically stores the session and attaches it to subsequent requests — you generally don't handle the secret manually.

**Server-side / SSR:** You manage the secret yourself, typically via an HTTP-only cookie:

```typescript
res.cookie('a_session_[PROJECT_ID]', session.secret, {
    httpOnly: true,
    secure: true,
    sameSite: 'strict',
    expires: new Date(session.expire),
    path: '/',
});
```

The cookie name **must** be `a_session_<PROJECT_ID>`. To use a session on a per-request basis, attach it to a fresh client:

```typescript
const sessionClient = new Client()
    .setEndpoint('...')
    .setProject('[PROJECT_ID]')
    .setSession(session);  // the secret

const user = await account.get();  // acts as the logged-in user
```

> **Important:** In SSR, create the **session client per-request** (never share it), but the admin client (API key) can be a reusable singleton. Use `setForwardedUserAgent()` to record the end-user's browser for security/debugging.

You can also inspect sessions:

```typescript
await account.getSession({ sessionId: 'current' });  // get a specific session
await account.listSessions();                         // list all active sessions
await account.updateSession({ sessionId: 'current' }); // refresh/extend (e.g. OAuth tokens)
```

## How Sessions Are Deleted

```typescript
// Log out the current session
await account.deleteSession({ sessionId: 'current' });

// Log out a specific session by ID
await account.deleteSession({ sessionId: '[SESSION_ID]' });

// Log out of ALL sessions (all devices)
await account.deleteSessions();
```

In SSR, remember to also clear the cookie after deleting the session.

## Session Limits

A few important constraints to be aware of:

- **Session length:** Configurable in the Appwrite Console under **Auth → Security**. The default is **1 year**, adjustable down to short-lived sessions. The `session.expire` field tells you exactly when it lapses.
- **Session limit per user:** Appwrite enforces a maximum number of active sessions per user (default **10**, configurable). When the limit is reached, creating a new session automatically **deletes the oldest** session — so a user signing in on an 11th device gets logged out of their first one.
- **Anonymous sessions** can be converted to permanent accounts by adding an email/password or OAuth identity (via `account.updateEmail()` / linking), preserving the user's data.

## Quick Reference

| Action | Method |
|--------|--------|
| Create (email/pass) | `account.createEmailPasswordSession()` |
| Create (OAuth, web) | `account.createOAuth2Session()` |
| Create (token exchange) | `account.createSession({ userId, secret })` |
| Get current user | `account.get()` |
| Get a session | `account.getSession({ sessionId })` |
| List sessions | `account.listSessions()` |
| Delete one session | `account.deleteSession({ sessionId })` |
| Delete all sessions | `account.deleteSessions()` |

